INSERT INTO `t_component` VALUES (4, '2.4.2', '{\"zh_CN\":\"表单\"}', 'ElForm', 'form', '表单包含 输入框, 单选框, 下拉选择, 多选框 等用户输入的组件。 使用表单，您可以收集、验证和提交数据。', '', '', '', '', 'proCode', '{\"package\":\"element-plus\",\"exportName\":\"ElForm\",\"destructuring\":true}', '表单组件', 'element-plus', NULL, '[{\"name\":{\"zh_CN\":\"表单\"},\"icon\":\"form\",\"screenshot\":\"\",\"snippetName\":\"ElForm\",\"schema\":{\"children\":[{\"componentName\":\"ElFormItem\",\"props\":{\"label\":\"账号\",\"prop\":\"account\"},\"children\":[{\"componentName\":\"ElInput\",\"props\":{\"modelValue\":\"\",\"placeholder\":\"请输入账号\"}}]},{\"componentName\":\"ElFormItem\",\"props\":{\"label\":\"密码\",\"prop\":\"password\"},\"children\":[{\"componentName\":\"ElInput\",\"props\":{\"modelValue\":\"\",\"placeholder\":\"请输入密码\",\"type\":\"password\"}}]},{\"componentName\":\"ElFormItem\",\"props\":{},\"children\":[{\"componentName\":\"ElButton\",\"props\":{\"type\":\"primary\",\"style\":\"margin-right: 10px\"},\"children\":[{\"componentName\":\"Text\",\"props\":{\"text\":\"提交\"}}]},{\"componentName\":\"ElButton\",\"props\":{\"type\":\"primary\"},\"children\":[{\"componentName\":\"Text\",\"props\":{\"text\":\"重置\"}}]}]}]}}]', '{\"properties\":[{\"name\":\"0\",\"label\":{\"zh_CN\":\"基础属性\"},\"content\":[{\"property\":\"model\",\"label\":{\"text\":{\"zh_CN\":\"数据对象\"}},\"description\":{\"zh_CN\":\"表单数据对象\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"top\",\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"rules\",\"label\":{\"text\":{\"zh_CN\":\"验证规则\"}},\"description\":{\"zh_CN\":\"表单验证规则\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"top\",\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"inline\",\"label\":{\"text\":{\"zh_CN\":\"行内模式\"}},\"description\":{\"zh_CN\":\"行内表单模式\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":