:\"right\"}]}}},{\"property\":\"show-message\",\"label\":{\"text\":{\"zh_CN\":\"显示校验信息\"}},\"description\":{\"zh_CN\":\"是否显示校验错误信息\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":true,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"inline-message\",\"label\":{\"text\":{\"zh_CN\":\"行内显示校验信息\"}},\"description\":{\"zh_CN\":\"是否以行内形式展示校验信息\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":false,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"status-icon\",\"label\":{\"text\":{\"zh_CN\":\"显示校验结果图标\"}},\"description\":{\"zh_CN\":\"是否在输入框中显示校验结果反馈图标\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":false,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"validate-on-rule-change\",\"label\":{\"text\":{\"zh_CN\":\"触发验证\"}},\"description\":{\"zh_CN\":\"是否在 rules 属性改变后立即触发一次验证\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":true,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"size\",\"label\":{\"text\":{\"zh_CN\":\"尺寸\"}},\"description\":{\"zh_CN\":\"用于控制该表单内组件的尺寸\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"defaultValue\":\"default\",\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"large\",\"value\":\"large\"},{\"label\":\"default\",\"value\":\"default\"},{\"label\":\"small\",\"value\":\"small\"}]}}},{\"property\":\"disabled\",\"label\":{\"text\":{\"zh_CN\":\"禁用\"}},\"description\":{\"zh_CN\":\"是否禁用该表单内的所有组件。 如果设置为 true, 它将覆盖内部组件的 disabled 属性\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":false,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}},\"device\":[]},{\"property\":\"scroll-to-error\",\"label\":{\"text\":{\"zh_CN\":\"滚动到错误项\"}},\"description\":{\"zh_CN\":\"当校验失败时，滚动到第一个错误表单项\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"defaultValue\":false,\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}},\"device\":[]}],\"description\":{\"zh_CN\":\"\"}}],\"events\":{\"onValidate\":{\"label\":{\"zh_CN\":\"任一表单项被校验后触发\"},\"description\":{\"zh_CN\":\"任一表单项被校验后触发\"},\"type\":\"event\",\"functionInfo\":{\"params\":[],\"returns\":{}},\"defaultValue\":\"\"}},\"slots\":{}}', '{\"loop\":true,\"condition\":true,\"styles\":true,\"isContainer\":true,\"isModal\":false,\"isPopper\":false,\"nestingRule\":{\"childWhitelist\":[\"ElFormItem\"],\"parentWhitelist\":\"\",\"descendantBlacklist\":\"\",\"ancestorWhitelist\":\"\"},\"isNullNode\":false,\"isLayout\":false,\"rootSelector\":\"\",\"shortcuts\":{\"properties\":[\"inline\",\"label-width\"]},\"contextMenu\":{\"actions\":[\"copy\",\"remove\",\"insert\",\"updateAttr\",\"bindEvent\",\"createBlock\"],\"disable\":[]},\"invalidity\":[\"\"],\"clickCapture\":true,\"framework\":\"Vue\"}', 1, 'Vue', 1, 1, 0, NULL, 2, '1', NULL, NULL, '1', '2025-08-03 19:54:13', '1', '2025-08-03 19:54:13');
INSERT INTO `t_component` VALUES (5, '2.4.2', '{\"zh_CN\":\"表单子项\"}', 'ElFormItem', 'formItem', '表单包含 输入框, 单选框, 下拉选择, 多选框 等用户输入的组件。 使用表单，您可以收集、验证和提交数据。', '', '', '', '', 'proCode', '{\"package\":\"element-plus\",\"exportName\":\"ElFormItem\",\"destructuring\":true}', '表单组件', 'element-plus', NULL, NULL, '{\"properties\":[{\"name\":\"0\",\"label\":{\"zh_CN\":\"基础属性\"},\"content\":[{\"property\":\"prop\",\"label\":{\"text\":{\"zh_CN\":\"键名\"}},\"description\":{\"zh_CN\":\"model 的键名。 它可以是一个属性的值(如 a.b.0 或 [a\', \'b\', \'0\'])。 在定义了 validate、resetFields 的方法时，该属性是必填的\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"label\",\"label\":{\"text\":{\"zh_CN\":\"标签文本\"}},\"description\":{\"zh_CN\":\"标签文本\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"label-width\",\"label\":{\"text\":{\"zh_CN\":\"标签宽度\"}},\"description\":{\"zh_CN\":\"标签宽度，例如 \'50px\'。 可以使用 auto\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"required\",\"label\":{\"text\":{\"zh_CN\":\"必填项\"}},\"description\":{\"zh_CN\":\"是否为必填项，如不设置，则会根据校验规则确认\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"rules\",\"label\":{\"text\":{\"zh_CN\":\"验证规则\"}},\"description\":{\"zh_CN\":\"表单验证规则, 更多内容可以参考async-validator\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"top\",\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"error\",\"label\":{\"text\":{\"zh_CN\":\"错误信息\"}},\"description\":{\"zh_CN\":\"表单域验证错误时的提示信息。设置该值会导致表单验证状态变为 error，并显示该错误信息\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"show-message\",\"label\":{\"text\":{\"zh_CN\":\"显示错误信息\"}},\"description\":{\"zh_CN\":\"是否显示校验错误信息\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"inline-message\",\"label\":{\"text\":{\"zh_CN\":\"行内显示错误信息\"}},\"description\":{\"zh_CN\":\"是否在行内显示校验信息\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"boolean\",\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"size\",\"label\":{\"text\":{\"zh_CN\":\"尺寸\"}},\"description\":{\"zh_CN\":\"用于控制该表单内组件的尺寸\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"defaultValue\":\"default\",\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"large\",\"value\":\"large\"},{\"label\":\"default\",\"value\":\"default\"},{\"label\":\"small\",\"value\":\"small\"}]}}},{\"property\":\"for\",\"label\":{\"text\":{\"zh_CN\":\"for\"}},\"description\":{\"zh_CN\":\"和原生标签相同能力\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"validate-status\",\"label\":{\"text\":{\"zh_CN\":\"校验状态\"}},\"description\":{\"zh_CN\":\"formItem 校验的状态\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"left\",\"type\":\"string\",\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"error\",\"value\":\"error\"},{\"label\":\"validating\",\"value\":\"validating\"},{\"label\":\"success\",\"value\":\"success\"}]}}}],\"description\":{\"zh_CN\":\"\"}}],\"events\":{},\"slots\":{\"label\":{\"label\":{\"zh_CN\":\"label\"},\"description\":{\"zh_CN\":\"标签位置显示的内容\"}},\"error\":{\"label\":{\"zh_CN\":\"error\"},\"description\":{\"zh_CN\":\"验证错误信息的显示内容\"}}}}', '{\"loop\":true,\"condition\":true,\"styles\":true,\"isContainer\":true,\"isModal\":false,\"isPopper\":false,\"nestingRule\":{\"childWhitelist\":\"\",\"parentWhitelist\":\"\",\"descendantBlacklist\":\"\",\"ancestorWhitelist\":\"\"},\"isNullNode\":false,\"isLayout\":false,\"rootSelector\":\"\",\"shortcuts\":{\"properties\":[\"inline\",\"label-width\"]},\"contextMenu\":{\"actions\":[\"copy\",\"remove\",\"insert\",\"updateAttr\",\"bindEvent\",\"createBlock\"],\"disable\":[]},\"invalidity\":[\"\"],\"clickCapture\":true,\"framework\":\"Vue\"}', 1, 'Vue', 1, 1, 0, NULL, 2, '1', NULL, NULL, '1', '2025-08-03 19:54:13', '1', '2025-08-03 19:54:13');
INSERT INTO `t_component` VALUES (6, '2.4.2', '{\"zh_CN\":\"表单\"}', 'ElTable', 'table', '用于展示多条结构类似的数据， 可对数据进行排序、筛选、对比或其他自定义操作', '', '', '', '', 'proCode', '{\"package\":\"element-plus\",\"exportName\":\"ElTable\",\"destructuring\":true}', '数据展示', 'element-plus', NULL, '[{\"name\":{\"zh_CN\":\"表格\"},\"icon\":\"grid\",\"screenshot\":\"\",\"snippetName\":\"ElTable\",\"schema\":{\"props\":{\"data\":[{\"date\":\"2016-05-03\",\"name\":\"Tom\",\"address\":\"No. 189, Grove St, Los Angeles\"},{\"date\":\"2016-05-02\",\"name\":\"Tom\",\"address\":\"No. 189, Grove St, Los Angeles\"},{\"date\":\"2016-05-04\",\"name\":\"Tom\",\"address\":\"No. 189, Grove St, Los Angeles\"},{\"date\":\"2016-05-01\",\"name\":\"Tom\",\"address\":\"No. 189, Grove St, Los Angeles\"}],\"columns\":[{\"type\":\"index\"},{\"label\":\"Date\",\"prop\":\"date\"},{\"label\":\"Name\",\"prop\":\"name\"},{\"label\":\"Address\",\"prop\":\"address\"}]}}}]', '{\"properties\":[{\"name\":\"0\",\"label\":{\"zh_CN\":\"基础属性\"},\"content\":[{\"property\":\"data\",\"label\":{\"text\":{\"zh_CN\":\"数据\"}},\"description\":{\"zh_CN\":\"显示的数据\"},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"labelPosition\":\"top\",\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"columns\",\"label\":{\"text\":{\"zh_CN\":\"表格列配置\"}},\"required\":true,\"readOnly\":false,\"disabled\":false,\"cols\":12,\"properties\":[{\"label\":{\"zh_CN\":\"默认分组\"},\"content\":[{\"property\":\"type\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"type\"}},\"description\":{\"text\":{\"zh_CN\":\"对应列的类型。 如果设置了selection则显示多选框； 如果设置了 index 则显示该行的索引（从 1 开始计算）； 如果设置了 expand 则显示为一个可展开的按钮\"}},\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"selection\",\"value\":\"selection\"},{\"label\":\"index\",\"value\":\"index\"},{\"label\":\"expand\",\"value\":\"expand\"}]}}},{\"property\":\"index\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"index\"}},\"description\":{\"text\":{\"zh_CN\":\"如果设置了 type=index，可以通过传递 index 属性来自定义索引\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{}}},{\"property\":\"label\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"label\"}},\"description\":{\"text\":{\"zh_CN\":\"显示的标题\"}},\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"column-key\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"column-key\"}},\"description\":{\"text\":{\"zh_CN\":\"column 的 key， column 的 key， 如果需要使用 filter-change 事件，则需要此属性标识是哪个 column 的筛选条件\"}},\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"prop\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"prop\"}},\"description\":{\"text\":{\"zh_CN\":\"字段名称 对应列内容的字段名， 也可以使用 property属性\"}},\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"width\",\"type\":\"number\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"width\"}},\"description\":{\"text\":{\"zh_CN\":\"对应列的宽度\"}},\"widget\":{\"component\":\"NumberConfigurator\",\"props\":{}}},{\"property\":\"min-width\",\"type\":\"number\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"min-width\"}},\"description\":{\"text\":{\"zh_CN\":\"对应列的最小宽度， 对应列的最小宽度， 与 width 的区别是 width 是固定的，min-width 会把剩余宽度按比例分配给设置了 min-width 的列\"}},\"widget\":{\"component\":\"NumberConfigurator\",\"props\":{}}},{\"property\":\"fixed\",\"type\":\"string\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"fixed\"}},\"description\":{\"text\":{\"zh_CN\":\"列是否固定在左侧或者右侧。 true 表示固定在左侧\"}},\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"left\",\"value\":\"left\"},{\"label\":\"right\",\"value\":\"right\"}]}}},{\"property\":\"sortable\",\"type\":\"boolean\",\"labelPosition\":\"left\",\"label\":{\"text\":{\"zh_CN\":\"sortable\"}},\"description\":{\"text\":{\"zh_CN\":\"对应列是否可以排序\"}},\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"sort-method\",\"type\":\"function\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"sort-method\"}},\"description\":{\"text\":{\"zh_CN\":\"指定数据按照哪个属性进行排序，仅当sortable设置为true的时候有效。 应该如同 Array.sort 那样返回一个 Number\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{}}},{\"property\":\"sort-by\",\"type\":\"array\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"sort-by\"}},\"description\":{\"text\":{\"zh_CN\":\"指定数据按照哪个属性进行排序，仅当 sortable 设置为 true 且没有设置 sort-method 的时候有效。 如果 sort-by 为数组，则先按照第 1 个属性排序，如果第 1 个相等，再按照第 2 个排序，以此类推\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"sort-orders\",\"type\":\"array\",\"labelPosition\":\"top\",\"label\":{\"text\":{\"zh_CN\":\"sort-orders\"}},\"description\":{\"text\":{\"zh_CN\":\"数据在排序时所使用排序策略的轮转顺序，仅当 sortable 为 true 时有效。 需传入一个数组，随着用户点击表头，该列依次按照数组中元素的顺序进行排序\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"language\":\"json\"}}},{\"property\":\"resizable\",\"type\":\"boolean\",\"labelPosition\":\"left\",\"defaultValue\":true,\"label\":{\"text\":{\"zh_CN\":\"resizable\"}},\"description\":{\"text\":{\"zh_CN\":\"对应列是否可以通过拖动改变宽度（需要在 el-table 上设置 border 属性为真）\"}},\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"formatter\",\"type\":\"function\",\"labelPosition\":\"top\",\"defaultValue\":true,\"label\":{\"text\":{\"zh_CN\":\"formatter\"}},\"description\":{\"text\":{\"zh_CN\":\"用来格式化内容\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{\"dataType\":\"JSFunction\"}}},{\"property\":\"show-overflow-tooltip\",\"type\":\"boolean\",\"labelPosition\":\"left\",\"defaultValue\":true,\"label\":{\"text\":{\"zh_CN\":\"show-overflow-tooltip\"}},\"description\":{\"text\":{\"zh_CN\":\"当内容过长被隐藏时显示 tooltip\"}},\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\"align\",\"type\":\"string\",\"labelPosition\":\"top\",\"defaultValue\":\"left\",\"label\":{\"text\":{\"zh_CN\":\"align\"}},\"description\":{\"text\":{\"zh_CN\":\"对齐方式\"}},\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"left\",\"value\":\"left\"},{\"label\":\"center\",\"value\":\"center\"},{\"label\":\"right\",\"value\":\"right\"}]}}},{\"property\":\"header-align\",\"type\":\"string\",\"labelPosition\":\"top\",\"defaultValue\":\"left\",\"label\":{\"text\":{\"zh_CN\":\"header-align\"}},\"description\":{\"text\":{\"zh_CN\":\"表头对齐方式， 若不设置该项，则使用表格的对齐方式\"}},\"widget\":{\"component\":\"SelectConfigurator\",\"props\":{\"options\":[{\"label\":\"left\",\"value\":\"left\"},{\"label\":\"center\",\"value\":\"center\"},{\"label\":\"right\",\"value\":\"right\"}]}}},{\"property\":\"class-name\",\"type\":\"string\",\"labelPosition\":\"top\",\"defaultValue\":\"left\",\"label\":{\"text\":{\"zh_CN\":\"class-name\"}},\"description\":{\"text\":{\"zh_CN\":\"列的 className\"}},\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"label-class-name\",\"type\":\"string\",\"labelPosition\":\"top\",\"defaultValue\":\"left\",\"label\":{\"text\":{\"zh_CN\":\"label-class-name\"}},\"description\":{\"text\":{\"zh_CN\":\"当前列标题的自定义类名\"}},\"widget\":{\"component\":\"InputConfigurator\",\"props\":{}}},{\"property\":\"selectable\",\"type\":\"function\",\"labelPosition\":\"top\",\"defaultValue\":true,\"label\":{\"text\":{\"zh_CN\":\"selectable\"}},\"description\":{\"text\":{\"zh_CN\":\"仅对 type=selection 的列有效，类型为 Function，Function 的返回值用来决定这一行的 CheckBox 是否可以勾选\"}},\"widget\":{\"component\":\"CodeConfigurator\",\"props\":{}}},{\"property\":\"reserve-selection\",\"type\":\"boolean\",\"labelPosition\":\"left\",\"defaultValue\":true,\"label\":{\"text\":{\"zh_CN\":\"reserve-selection\"}},\"description\":{\"text\":{\"zh_CN\":\"数据刷新后是否保留选项，仅对  type=selection 的列有效， 请注意， 需指定 row-key 来让这个功能生效。\"}},\"widget\":{\"component\":\"CheckBoxConfigurator\",\"props\":{}}},{\"property\":\